const genericTLDs = ['.com', '.org', '.net', '.io', '.co', '.app', '.dev', '.tech', '.ai', '.info', '.biz', '.xyz', '.online', '.site', '.cloud', '.digital', '.global', '.world', '.pro', '.solutions'];

const data = $('Prepare Company Data').item.json;
const domain = (data.domain || '').toLowerCase().trim();
let countryFromTLD = '';

if (domain) {
  for (const [tld, country] of Object.entries(tldMap)) {
    if (tld.includes('.') && tld.split('.').length > 2 && domain.endsWith(tld)) {
      countryFromTLD = country;
      break;
    }
  }
  if (!countryFromTLD) {
    const lastDot = domain.lastIndexOf('.');
    if (lastDot !== -1) {
      const tld = domain.substring(lastDot);
      if (!genericTLDs.includes(tld) && tldMap[tld]) {
        countryFromTLD = tldMap[tld];
      }
    }
  }
}

return { json: { ...data, countryFromTLD } };

